mapper.select:
SELECT t.id, t.test_key, t.title, t.description, t.thumbnail_image, t.category, c.display_name AS category_display_name, t.test_type, t.estimated_time, t.status, t.created_by, t.play_count, t.created_at, t.updated_at, COUNT(q.id) AS question_count FROM md_tests t LEFT JOIN md_test_questions q ON t.id = q.test_id AND q.is_active = 1 LEFT JOIN md_test_category c ON t.category = c.category_name
AND t.created_by = #{createdBy}
GROUP BY t.id ORDER BY t.created_at DESC

mapper.insert:
INSERT INTO md_tests (
    test_key, title, description, thumbnail_image,
    category, test_type, estimated_time, status, created_by
) VALUES (
    #{testKey}, #{title}, #{description}, #{thumbnailImage},
    #{category}, #{testType}, #{estimatedTime}, #{status}, #{createdBy}
)

INSERT INTO md_test_questions (
    test_id, question_order, question_text, domain, is_reverse, is_active
) VALUES (
    #{testId}, #{questionOrder}, #{questionText}, #{domain}, #{reverse}, #{active}
)

mapper.update:
UPDATE md_test_questions SET
    question_text = #{questionText},
    domain        = #{domain},
    is_reverse    = #{reverse}
WHERE id = #{id}

mapper.insert:
INSERT INTO md_test_results (
    test_id, result_title, result_content, result_image, min_score, max_score
) VALUES (
    #{testId}, #{resultTitle}, #{resultContent}, #{resultImage}, #{minScore}, #{maxScore}
)

mapper.select:
SELECT * FROM ( SELECT CONVERT('NORMAL' USING utf8mb4) as type, CAST(t.id AS CHAR) as id, CONVERT(t.test_key USING utf8mb4) as `key`, CONVERT(t.title USING utf8mb4) as title, CONVERT(t.description USING utf8mb4) as description, CONVERT(t.thumbnail_image USING utf8mb4) as thumbnail, CONVERT(NULL USING utf8mb4) as thumbnail2, CONVERT(t.category USING utf8mb4) as categoryId, CONVERT(COALESCE(c.display_name, t.category) USING utf8mb4) as categoryName, t.play_count as playCount, t.created_at as createdAt, (CASE WHEN DATEDIFF(NOW(), t.created_at) <= 14 THEN 1 ELSE 0 END) as isNew, 0 as isSpicy FROM md_tests t LEFT JOIN md_test_category c ON t.category = c.category_name WHERE t.status = 'active'
UNION ALL
SELECT CONVERT('BALANCE' USING utf8mb4) as type, CAST(bq.id AS CHAR) as id, CAST(bq.id AS CHAR) as `key`, CONVERT(bq.title USING utf8mb4) as title, CONVERT(bq.title USING utf8mb4) as description, CONVERT(bq.option_1_image_path USING utf8mb4) as thumbnail, CONVERT(bq.option_2_image_path USING utf8mb4) as thumbnail2, CONVERT(bq.category USING utf8mb4) as categoryId, CONVERT(COALESCE(c2.display_name, bq.category) USING utf8mb4) as categoryName, bq.total_count as playCount, bq.created_at as createdAt, (CASE WHEN DATEDIFF(NOW(), bq.created_at) <= 14 THEN 1 ELSE 0 END) as isNew, bq.is_spicy as isSpicy FROM balance_questions bq LEFT JOIN md_test_category c2 ON bq.category = c2.category_name WHERE bq.status = 'active'
UNION ALL
SELECT CONVERT('EGEN' USING utf8mb4) as type, CAST('egen1' AS CHAR) as id, CONVERT('selectEgenTetoGame' USING utf8mb4) as `key`, CONVERT('에겐테토 성격 검사' USING utf8mb4) as title, CONVERT('나의 본모습을 찾아가는 정밀 성격 분석 테스트' USING utf8mb4) as description, CONVERT('/assets/img/egenTeto/egenTetoMain.png' USING utf8mb4) as thumbnail, CONVERT(NULL USING utf8mb4) as thumbnail2, CONVERT('selectEgenTetoGame' USING utf8mb4) as categoryId, CONVERT('심리/성격' USING utf8mb4) as categoryName, (SELECT COUNT(*) FROM egen_teto_test_result) as playCount, CONVERT('2024-01-01 00:00:00' USING utf8mb4) as createdAt, 0 as isNew, 0 as isSpicy FROM DUAL ) combined
AND categoryId = #{category}
AND type IN ('NORMAL', 'EGEN')
AND type = #{type}
ORDER BY playCount DESC ORDER BY createdAt DESC
LIMIT #{limit} OFFSET #{offset}
